# Comprehensive Code Analysis Report

## Executive Summary

The project is a Python-based AI code analysis tool that uses Anthropic's Claude API. The codebase contains **critical bugs, incomplete implementations, architectural issues, and security vulnerabilities** that prevent it from functioning correctly.

---

## 1. Critical Errors

### 1.1 `ContextBuilder.py` — Truncated File / Incomplete Implementation

**Error: File is cut off mid-statement**
```python
# Line at end of file:
context_chu  # ← SyntaxError: incomplete variable name
```

**Error: Method signature mismatch**

The `build_project_context` method calls `add_metadata(context_chunks, project_path)` with two arguments, but the old version (visible in `project_context.txt`) defines it as:
```python
def add_metadata(self, context_chunks):  # ← Missing project_path parameter
    pass
```

**Error: Missing method implementations**

Methods called in `build_project_context` that are either stubs or missing entirely:
```python
# Called but not implemented:
self.add_dependencies(context_chunks, project_path)
self.add_cicd_configs(context_chunks, project_path)
self.add_readme_and_license(context_chunks, project_path)
self.add_statistics(context_chunks, project_path)
```

**Error: Duplicate entry in `ignore_dirs`**
```python
self.ignore_dirs = {
    '__pycache__', ..., '__pycache__',  # ← Duplicate (harmless in set, but indicates copy-paste error)
}
```

**Fix:**
```python
import logging
import os
import json
from pathlib import Path


class ContextBuilder:
    def __init__(self):
        self.logger = logging.getLogger(__name__)
        self.valid_extensions = {
            '.py', '.js', '.jsx', '.ts', '.tsx', '.html', '.css', '.scss', '.json',
            '.yaml', '.yml', '.md', '.txt', '.xml', '.sql', '.java', '.cpp', '.c',
            '.h', '.hpp', '.go', '.rs', '.rb', '.php', '.sh', '.bash', '.pl', '.pm'
        }
        self.ignore_dirs = {
            '__pycache__', '.git', 'node_modules', '.svn', '.hg', '.idea',
            '.vscode', 'venv', '.venv', 'env', '.env', '.pytest_cache',
            'dist', 'build', '.tox', '.coverage', '.mypy_cache', '.DS_Store', '.qodo'
        }
        self.max_file_size = 1024 * 1024

    def build_project_context(self, project_dir: str) -> dict:
        project_path = Path(project_dir)
        if not project_path.exists():
            raise FileNotFoundError(f"Directory does not exist: {project_dir}")

        context_chunks = {
            'metadata': {},
            'tree_structure': '',
            'file_contents': {},
            'dependencies': {},
            'cicd_configs': {},
            'readme': '',
            'license': '',
            'stats': {}
        }

        try:
            self._add_metadata(context_chunks, project_path)
            self._add_tree_structure(context_chunks, project_path)
            self._add_file_contents(context_chunks, project_path)
            self._add_dependencies(context_chunks, project_path)
            self._add_cicd_configs(context_chunks, project_path)
            self._add_readme_and_license(context_chunks, project_path)
            self._add_statistics(context_chunks)
        except Exception as e:
            self.logger.error(f"Error building project context: {e}")
            raise

        return context_chunks

    def build_prompt_context(self, project_dir: str) -> str:
        """Build a single string prompt context for AI models."""
        context = self.build_project_context(project_dir)
        parts = []

        parts.append(f"=== PROJECT ANALYSIS ===")
        parts.append(f"Project: {context['metadata'].get('project_name', 'Unknown')}")
        parts.append(f"Type: {context['metadata'].get('project_type', 'Unknown')}")

        parts.append("\n=== PROJECT STRUCTURE ===")
        parts.append(context.get('tree_structure', ''))

        if context.get('readme'):
            parts.append("\n=== README ===")
            parts.append(context['readme'])

        if context.get('dependencies'):
            parts.append("\n=== DEPENDENCIES ===")
            parts.append(json.dumps(context['dependencies'], indent=2))

        parts.append("\n=== FILE CONTENTS ===")
        for rel_path, content in context.get('file_contents', {}).items():
            parts.append(f"\n--- START: {rel_path} ---")
            parts.append(content)
            parts.append(f"--- END: {rel_path} ---")

        return "\n".join(parts)

    def _add_metadata(self, context_chunks: dict, project_path: Path) -> None:
        context_chunks['metadata'] = {
            'project_name': project_path.name,
            'project_path': str(project_path.resolve()),
            'project_type': self._detect_project_type(project_path)
        }

    def _detect_project_type(self, project_path: Path) -> str:
        if (project_path / 'package.json').exists():
            return 'Node.js'
        if (project_path / 'requirements.txt').exists():
            return 'Python'
        if (project_path / 'go.mod').exists():
            return 'Go'
        if (project_path / 'pom.xml').exists():
            return 'Java Maven'
        if (project_path / 'Cargo.toml').exists():
            return 'Rust'
        return 'Unknown'

    def _add_tree_structure(self, context_chunks: dict, project_path: Path) -> None:
        context_chunks['tree_structure'] = self._generate_tree(project_path)

    def _generate_tree(self, current_dir: Path, indent: str = "") -> str:
        tree = ""
        try:
            items = sorted(current_dir.iterdir(), key=lambda p: (p.is_file(), p.name))
        except PermissionError:
            self.logger.warning(f"Permission denied: {current_dir}")
            return tree

        items_list = [i for i in items if i.name not in self.ignore_dirs]
        for idx, item in enumerate(items_list):
            is_last = (idx == len(items_list) - 1)
            connector = '└── ' if is_last else '├── '
            child_indent = indent + ("    " if is_last else "│   ")

            if item.is_dir():
                tree += f"{indent}{connector}[{item.name}/]\n"
                tree += self._generate_tree(item, child_indent)
            else:
                tree += f"{indent}{connector}{item.name}\n"

        return tree

    def _add_file_contents(self, context_chunks: dict, project_path: Path) -> None:
        for root, dirs, files in os.walk(project_path):
            dirs[:] = [d for d in dirs if d not in self.ignore_dirs]

            for file_name in sorted(files):
                file_path = Path(root) / file_name
                if file_path.suffix.lower() not in self.valid_extensions:
                    continue

                try:
                    if file_path.stat().st_size > self.max_file_size:
                        self.logger.warning(f"File skipped (>1MB): {file_path}")
                        continue
                except OSError:
                    continue

                rel_path = str(file_path.relative_to(project_path))
                try:
                    content = file_path.read_text(encoding='utf-8', errors='replace')
                    context_chunks['file_contents'][rel_path] = content
                except Exception as e:
                    self.logger.warning(f"Error reading {file_path}: {e}")

    def _add_dependencies(self, context_chunks: dict, project_path: Path) -> None:
        deps = {}

        req_file = project_path / 'requirements.txt'
        if req_file.exists():
            try:
                deps['requirements.txt'] = req_file.read_text(encoding='utf-8')
            except Exception as e:
                self.logger.warning(f"Error reading requirements.txt: {e}")

        pkg_file = project_path / 'package.json'
        if pkg_file.exists():
            try:
                deps['package.json'] = json.loads(pkg_file.read_text(encoding='utf-8'))
            except Exception as e:
                self.logger.warning(f"Error reading package.json: {e}")

        context_chunks['dependencies'] = deps

    def _add_cicd_configs(self, context_chunks: dict, project_path: Path) -> None:
        cicd = {}
        patterns = [
            '.github/workflows',
            '.gitlab-ci.yml',
            'Jenkinsfile',
            '.travis.yml',
            'Dockerfile',
            'docker-compose.yml',
        ]
        for pattern in patterns:
            path = project_path / pattern
            if path.exists():
                if path.is_dir():
                    for f in path.glob('*.yml'):
                        try:
                            cicd[str(f.relative_to(project_path))] = f.read_text(encoding='utf-8')
                        except Exception as e:
                            self.logger.warning(f"Error reading {f}: {e}")
                else:
                    try:
                        cicd[pattern] = path.read_text(encoding='utf-8')
                    except Exception as e:
                        self.logger.warning(f"Error reading {pattern}: {e}")
        context_chunks['cicd_configs'] = cicd

    def _add_readme_and_license(self, context_chunks: dict, project_path: Path) -> None:
        for name in ['README.md', 'README.rst', 'README.txt', 'README']:
            readme = project_path / name
            if readme.exists():
                try:
                    context_chunks['readme'] = readme.read_text(encoding='utf-8')
                    break
                except Exception as e:
                    self.logger.warning(f"Error reading {name}: {e}")

        for name in ['LICENSE', 'LICENSE.txt', 'LICENSE.md']:
            lic = project_path / name
            if lic.exists():
                try:
                    context_chunks['license'] = lic.read_text(encoding='utf-8')
                    break
                except Exception as e:
                    self.logger.warning(f"Error reading {name}: {e}")

    def _add_statistics(self, context_chunks: dict) -> None:
        file_contents = context_chunks.get('file_contents', {})
        ext_counts: dict = {}
        total_lines = 0

        for rel_path, content in file_contents.items():
            ext = Path(rel_path).suffix.lower()
            ext_counts[ext] = ext_counts.get(ext, 0) + 1
            total_lines += content.count('\n')

        context_chunks['stats'] = {
            'total_files': len(file_contents),
            'total_lines': total_lines,
            'files_by_extension': ext_counts
        }
```

